import { CheckCircle, Clock, PauseCircle, Truck, XCircle, Hourglass } from 'lucide-react';

export const STATUS_OPTIONS = ['Pending Approval', 'Booked', 'In Transit', 'Delivered', 'On Hold', 'Cancelled'];

export const statusMeta = {
  'Pending Approval': {
    badge: 'warning',
    Icon: Hourglass,
  },
  Booked: {
    badge: 'primary',
    Icon: Clock,
  },
  'In Transit': {
    badge: 'info',
    Icon: Truck,
  },
  'On Hold': {
    badge: 'warning',
    Icon: PauseCircle,
  },
  Delivered: {
    badge: 'success',
    Icon: CheckCircle,
  },
  Cancelled: {
    badge: 'danger',
    Icon: XCircle,
  },
};

export function getStatusBadge(status) {
  return statusMeta[status]?.badge || 'secondary';
}

export function getStatusIcon(status) {
  return statusMeta[status]?.Icon || XCircle;
}
